n,m = map(int,input().split())
s = []
for i in range(n):
    s.append(input())
def palindrome(s):
    for i in range(len(s)//2):
        if s[i] != s[-1-i]:
            return False
    return True
ans = ""
for i in range(n):
    for j in range(n):
        if i == j:
            continue
        else:
            if palindrome(s[i]+s[j]):
                if len(s[i]+s[j]) > len(ans):
                    ans = s[i]+s[j]
if ans == "":
    print(0)
else:
    print(len(ans))
    print(ans)
